#include <stdio.h>
#include <stdbool.h>

#define TOTAL_BLOCKS 32

typedef struct {
    unsigned int bitmap[TOTAL_BLOCKS / 32];
    int total_blocks;
} BitVector;

// Initialize bit vector - all blocks free
void init(BitVector *bv) {
    bv->total_blocks = TOTAL_BLOCKS;
    for (int i = 0; i < TOTAL_BLOCKS/32; i++) {
        bv->bitmap[i] = 0;  // 0 means free
    }
}

// Allocate first n free blocks
int* allocate_blocks(BitVector *bv, int n) {
    static int allocated[TOTAL_BLOCKS];
    int count = 0;

    for (int i = 0; i < TOTAL_BLOCKS && count < n; i++) {
        int word = i / 32;
        int bit = i % 32;
        if ((bv->bitmap[word] & (1 << bit)) == 0) {
            // Block is free, allocate it
            bv->bitmap[word] |= (1 << bit);
            allocated[count++] = i;
        }
    }
    allocated[count] = -1;  // Mark end
    return allocated;
}

// Free allocated blocks
void free_blocks(BitVector *bv, int *blocks) {
    for (int i = 0; blocks[i] != -1; i++) {
        int block_num = blocks[i];
        int word = block_num / 32;
        int bit = block_num % 32;
        bv->bitmap[word] &= ~(1 << bit);  // Set to 0 (free)
    }
}

// Display bit vector
void display(BitVector *bv) {
    printf("Bit Vector: ");
    for (int i = 0; i < TOTAL_BLOCKS; i++) {
        int word = i / 32;
        int bit = i % 32;
        printf("%d", (bv->bitmap[word] & (1 << bit)) ? 1 : 0);
    }
    printf("\n");
}

int main() {
    BitVector bv;
    init(&bv);

    display(&bv);

    int blocks1[] = {5, 10, 15};
    for (int i = 0; i < 3; i++) {
        int word = blocks1[i] / 32;
        int bit = blocks1[i] % 32;
        bv.bitmap[word] |= (1 << bit);
    }

    display(&bv);

    return 0;
}
